test('dashboard app works', async ({ page }) => {
  // Header exists
  await expect(page.locator('header, [role=banner], nav').first()).toBeVisible();

  // Stat cards
  const cards = page.locator('[class*=card], [class*=stat], [class*=metric]');
  await expect(cards.first()).toBeVisible();

  // Table with data
  const table = page.locator('table');
  await expect(table).toBeVisible();
  const rows = table.locator('tbody tr');
  expect(await rows.count()).toBeGreaterThanOrEqual(3);

  // Theme toggle
  const toggle = page.getByRole('button', { name: /theme|dark|light|mode/i });
  if (await toggle.isVisible()) {
    await toggle.click();
    // Verify some visual change happened
    const html = page.locator('html');
    const classAfter = await html.getAttribute('class');
    // Either class changed or data-theme changed
  }
});
